      if (tokens.isExpired) {
        // Try to refresh the token
        final refreshed = await _refreshTokens(tokens.refreshToken);
        if (refreshed != null) {
          _state = AuthState(
            status: AuthStatus.authenticated,
            user: user,
            tokens: refreshed,
          );
          await _persistSession(user, refreshed);
          _scheduleTokenRefresh(refreshed);
        } else {
          await _clearSession();
          _state = const AuthState(status: AuthStatus.unauthenticated);
        }
      } else {
        _state = AuthState(
          status: AuthStatus.authenticated,
          user: user,
          tokens: tokens,
        );
        _scheduleTokenRefresh(tokens);
      }

      notifyListeners();
    } catch (e) {
      _state = AuthState(
        status: AuthStatus.unauthenticated,
        errorMessage: 'Failed to restore session: $e',
      );
      notifyListeners();
    }
  }

