  Future<void> _persistSession(User user, AuthTokens tokens) async {
    final prefs = _prefs;
    if (prefs == null) return;

    await prefs.setString(_keyUser, jsonEncode(user.toJson()));
    await prefs.setString(_keyTokens, jsonEncode(tokens.toJson()));
